import sys
sys.path[:] = [x for x in sys.path if x]
import os, functools, http.server
args = sys.argv[1:]
directory = None; port = 8000; rest = []
i = 0
while i < len(args):
    a = args[i]
    if a in ('--directory', '-d'):
        i += 1; directory = args[i]
    elif a.startswith('--directory='):
        directory = a.split('=', 1)[1]
    else:
        rest.append(a)
    i += 1
if directory is None and rest: directory = rest.pop(0)
if rest: port = int(rest[0])
try:
    os.chdir(directory)
except OSError:
    pass
http.server.ThreadingHTTPServer.allow_reuse_address = True
http.server.ThreadingHTTPServer(('', port),
    functools.partial(http.server.SimpleHTTPRequestHandler, directory=directory)).serve_forever()

